sp_angular_provider.script:
function scmTablePreferencesService() {
    "use strict";

    function savePreference(options) {
        options = options || {};

        if (!options.canSavePreferences) {
            return Promise.resolve();
        }

        return options.server.get({
            action: "savePreference",
            transactionId: options.transactionId,
            tableProviderScriptInclude: options.tableProviderScriptInclude,
            preferenceName: options.preferenceName,
            preferenceValue: options.preferenceValue,
        });
    }

    function getTableColumns(options) {
        options = options || {};

        return options.server
            .get({
                action: "getTableColumns",
                transactionId: options.transactionId,
                tableProviderScriptInclude: options.tableProviderScriptInclude,
            })
            .then(function (response) {
                return response.data.columns || [];
            });
    }

    function revertListViewToDefault(options) {
        options = options || {};

        return options.server
            .get({
                action: "revertListViewToDefault",
                transactionId: options.transactionId,
                tableProviderScriptInclude: options.tableProviderScriptInclude,
            })
            .then(function (response) {
                return response.data.columns || [];
            });
    }

    return {
        savePreference: savePreference,
        getTableColumns: getTableColumns,
        revertListViewToDefault: revertListViewToDefault,
    };
}
